//! frffmpeg CLI — sovereign ffmpeg surface (frf-powered).
//!
//!   frffmpeg generate <scene_idx> <out.mp4> [seed]   # render gnosis scene -> H.264
//!   frffmpeg <scene_idx> <out.mp4> [seed]            # back-compat alias for `generate`
//!   frffmpeg concat <out.mp4> <input.mp4>...         # normalize + stitch MP4 clips
//!   frffmpeg probe <video>                           # ffprobe -> dims/fps/duration/frames
//!   frffmpeg decode <video> [opts]                   # decode RGB24 frames, report + optional dump
//!
//! decode opts:
//!   --fps <f>          resample output to f fps (frame stride)
//!   --scale <WxH>      scale output frames
//!   --start <s>        seek to s seconds before decoding
//!   --max <n>          stop after n frames
//!   --dump-dir <dir>   write each frame as <dir>/frame_NNNNNN.ppm (P6)

use frffmpeg::concat::concat_videos;
use frffmpeg::decode::{DecodeOptions, Decoder, probe};
use frffmpeg::generate::generate_video;
use std::fs;
use std::io::{self, Write};
use std::time::Instant;

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        usage_and_exit();
    }

    // Back-compat: `frffmpeg <scene_idx> <out> [seed]` (first arg is a number).
    if args[1].parse::<usize>().is_ok() {
        return run_generate(&args[1..]);
    }

    match args[1].as_str() {
        "generate" => run_generate(&args[2..]),
        "concat" => run_concat(&args[2..]),
        "probe" => run_probe(&args[2..]),
        "decode" => run_decode(&args[2..]),
        other => {
            eprintln!("frffmpeg: unknown subcommand '{other}'");
            usage_and_exit();
        }
    }
}

fn usage_and_exit() -> ! {
    eprintln!(
        "Usage:\n  \
         frffmpeg generate <scene_idx> <out.mp4> [seed]\n  \
         frffmpeg <scene_idx> <out.mp4> [seed]\n  \
         frffmpeg concat <out.mp4> <input.mp4>...\n  \
         frffmpeg probe <video>\n  \
         frffmpeg decode <video> [--fps f] [--scale WxH] [--start s] [--max n] [--dump-dir dir]"
    );
    std::process::exit(1);
}

fn run_concat(rest: &[String]) {
    if rest.len() < 2 {
        eprintln!("frffmpeg concat: need <out.mp4> <input.mp4>...");
        std::process::exit(1);
    }

    let out_path = &rest[0];
    let input_paths = rest[1..].to_vec();
    if let Err(error) = concat_videos(out_path, &input_paths) {
        eprintln!("frffmpeg concat: {error}");
        std::process::exit(1);
    }
}

fn run_generate(rest: &[String]) {
    if rest.len() < 2 {
        eprintln!("frffmpeg generate: need <scene_idx> <out.mp4> [seed]");
        std::process::exit(1);
    }
    let scene_idx: usize = rest[0].parse().unwrap_or_else(|_| {
        eprintln!("frffmpeg generate: scene_idx must be a number");
        std::process::exit(1);
    });
    let out_path = &rest[1];
    let seed: f32 = rest.get(2).and_then(|s| s.parse().ok()).unwrap_or(0.0);
    generate_video(scene_idx, out_path, seed);
}

fn run_probe(rest: &[String]) {
    let Some(path) = rest.first() else {
        eprintln!("frffmpeg probe: need <video>");
        std::process::exit(1);
    };
    match probe(path) {
        Ok(info) => {
            println!("path      : {path}");
            println!("dimensions: {}x{}", info.width, info.height);
            println!(
                "fps       : {:.3} ({}/{})",
                info.fps(),
                info.fps_num,
                info.fps_den
            );
            println!("duration  : {:.3}s", info.duration_s);
            println!("nb_frames : {}", info.nb_frames);
        }
        Err(e) => {
            eprintln!("frffmpeg probe: {e}");
            std::process::exit(1);
        }
    }
}

fn run_decode(rest: &[String]) {
    let mut path: Option<String> = None;
    let mut opts = DecodeOptions::default();
    let mut dump_dir: Option<String> = None;

    let mut i = 0;
    while i < rest.len() {
        match rest[i].as_str() {
            "--fps" => {
                opts.fps = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--scale" => {
                if let Some(s) = rest.get(i + 1) {
                    if let Some((w, h)) = s.split_once('x') {
                        if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) {
                            opts.scale = Some((w, h));
                        }
                    }
                }
                i += 2;
            }
            "--start" => {
                opts.start_s = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--max" => {
                opts.max_frames = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--dump-dir" => {
                dump_dir = rest.get(i + 1).cloned();
                i += 2;
            }
            other => {
                if path.is_none() {
                    path = Some(other.to_string());
                }
                i += 1;
            }
        }
    }

    let Some(path) = path else {
        eprintln!("frffmpeg decode: need <video>");
        std::process::exit(1);
    };

    if let Some(dir) = &dump_dir {
        if let Err(e) = fs::create_dir_all(dir) {
            eprintln!("frffmpeg decode: cannot create dump dir '{dir}': {e}");
            std::process::exit(1);
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => {
            eprintln!("frffmpeg decode: probe failed: {e}");
            std::process::exit(1);
        }
    };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => {
            eprintln!("frffmpeg decode: open failed: {e}");
            std::process::exit(1);
        }
    };
    let (out_w, out_h) = dec.dimensions();

    let t0 = Instant::now();
    let mut count: u64 = 0;
    let mut bytes: u64 = 0;
    let mut last_pts = 0.0f64;
    let mut checksum: u64 = 0; // cheap content fingerprint, proves frames differ

    for f in dec {
        let f = match f {
            Ok(f) => f,
            Err(e) => {
                eprintln!("frffmpeg decode: {e}");
                break;
            }
        };
        count += 1;
        bytes += f.rgb.len() as u64;
        last_pts = f.pts_s;
        // sample-sum a sparse set of pixels for a fingerprint (not a full hash)
        let mut s: u64 = 0;
        let step = (f.rgb.len() / 997).max(1);
        let mut k = 0;
        while k < f.rgb.len() {
            s = s.wrapping_add(f.rgb[k] as u64);
            k += step;
        }
        checksum ^= s.wrapping_mul(f.index.wrapping_add(1));

        if let Some(dir) = &dump_dir {
            if let Err(e) = write_ppm(dir, &f.rgb, out_w, out_h, f.index) {
                eprintln!("frffmpeg decode: dump failed: {e}");
                break;
            }
        }
    }

    let dt = t0.elapsed().as_secs_f64();
    let fps = if dt > 0.0 { count as f64 / dt } else { 0.0 };
    println!("decoded   : {count} frames @ {out_w}x{out_h}");
    println!("bytes      : {bytes} ({:.1} MiB)", bytes as f64 / 1.048_576e6);
    println!("last_pts   : {last_pts:.3}s");
    println!("decode time: {dt:.3}s  ({fps:.1} frames/s, cold)");
    println!("fingerprint: {checksum:016x}");
    if let Some(dir) = &dump_dir {
        println!("dumped     : {count} PPM frames -> {dir}");
    }
}

/// Write a packed-RGB24 frame as a binary PPM (P6) — no image-crate dependency.
fn write_ppm(dir: &str, rgb: &[u8], w: u32, h: u32, index: u64) -> io::Result<()> {
    let path = format!("{dir}/frame_{index:06}.ppm");
    let mut f = fs::File::create(path)?;
    write!(f, "P6\n{w} {h}\n255\n")?;
    f.write_all(rgb)?;
    Ok(())
}
